-- ============================================================================
-- Quiz Seed: Luke — Part 1 (Chapters 1–6)
-- 3 difficulties × 6 chapters = 96 total questions
--   kids:   3 per chapter  = 18
--   teens:  5 per chapter  = 30
--   adults: 8 per chapter  = 48
-- ============================================================================

-- ═══════════════ CHAPTERS 1–3 ═══════════════

-- ═══ Luke Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 1, 'kids', 1, 'What angel appeared to Zacharias in the temple?', 'Gabriel', 'Michael', 'Raphael', 'Uriel', 'a', 'Luke 1:19 — "I am Gabriel, that stand in the presence of God; and am sent to speak unto thee, and to shew thee these glad tidings."'),
('Luke', 1, 'kids', 2, 'What was the name of the baby that the angel said Mary would have?', 'Jesus', 'John', 'Samuel', 'David', 'a', 'Luke 1:31 — "And, behold, thou shalt conceive in thy womb, and bring forth a son, and shalt call his name JESUS."'),
('Luke', 1, 'kids', 3, 'What happened to Zacharias because he did not believe the angel?', 'He could not speak until the baby was born', 'He fell asleep', 'He ran away', 'He became very sick', 'a', 'Luke 1:20 — "And, behold, thou shalt be dumb, and not able to speak, until the day that these things shall be performed, because thou believest not my words."'),
-- Teens
('Luke', 1, 'teens', 1, 'What did the angel Gabriel say to Mary about her favour with God?', 'Hail, thou that art highly favoured, the Lord is with thee: blessed art thou among women', 'You are the richest woman in Israel', 'You have been chosen as a queen', 'You are wiser than all the prophets', 'a', 'Luke 1:28 — "And the angel came in unto her, and said, Hail, thou that art highly favoured, the Lord is with thee: blessed art thou among women."'),
('Luke', 1, 'teens', 2, 'How did the angel explain that Mary would conceive while being a virgin?', 'The Holy Ghost shall come upon thee, and the power of the Highest shall overshadow thee', 'By a special potion from the temple', 'Through a visit from an earthly king', 'By eating sacred bread', 'a', 'Luke 1:35 — "The Holy Ghost shall come upon thee, and the power of the Highest shall overshadow thee: therefore also that holy thing which shall be born of thee shall be called the Son of God."'),
('Luke', 1, 'teens', 3, 'What famous statement did the angel make about God''s power?', 'For with God nothing shall be impossible', 'God only helps those who help themselves', 'God works only through human effort', 'God''s power has limits on earth', 'a', 'Luke 1:37 — "For with God nothing shall be impossible."'),
('Luke', 1, 'teens', 4, 'What did Mary say when she began to praise God?', 'My soul doth magnify the Lord, and my spirit hath rejoiced in God my Saviour', 'I am the greatest woman in Israel', 'I deserve this honour more than anyone', 'I have earned this by my good works', 'a', 'Luke 1:46-47 — "And Mary said, My soul doth magnify the Lord, And my spirit hath rejoiced in God my Saviour."'),
('Luke', 1, 'teens', 5, 'What happened when Zacharias wrote "His name is John" on a writing table?', 'His mouth was opened immediately and he spake, and praised God', 'He fell into a deep sleep', 'The writing table broke in half', 'Nothing happened until the next day', 'a', 'Luke 1:63-64 — "And he asked for a writing table, and wrote, saying, His name is John. And they marvelled all. And his mouth was opened immediately, and his tongue loosed, and he spake, and praised God."'),
-- Adults
('Luke', 1, 'adults', 1, 'How does Luke describe the purpose of his Gospel in the opening verses?', 'To write an orderly account so that Theophilus might know the certainty of those things wherein he was instructed', 'To replace all previous accounts of Jesus'' life', 'To provide a legal defence for Paul', 'To create a liturgical text for temple worship', 'a', 'Luke 1:3-4 — "It seemed good to me also, having had perfect understanding of all things from the very first, to write unto thee in order, most excellent Theophilus, That thou mightest know the certainty of those things, wherein thou hast been instructed."'),
('Luke', 1, 'adults', 2, 'What was Zacharias doing when the angel appeared to him?', 'Burning incense in the temple of the Lord, his lot having been chosen by priestly custom', 'Reading the Torah in the synagogue', 'Baptising people in the Jordan', 'Offering a lamb on the altar', 'a', 'Luke 1:9-11 — "According to the custom of the priest''s office, his lot was to burn incense when he went into the temple of the Lord. And there appeared unto him an angel of the Lord standing on the right side of the altar of incense."'),
('Luke', 1, 'adults', 3, 'What does the angel say about John the Baptist''s ministry in relation to the coming Messiah?', 'He shall go before him in the spirit and power of Elias, to turn the hearts of the fathers to the children and the disobedient to the wisdom of the just', 'He shall be a military leader who conquers Rome', 'He shall become the high priest of Israel', 'He shall write new scriptures for the nation', 'a', 'Luke 1:17 — "And he shall go before him in the spirit and power of Elias, to turn the hearts of the fathers to the children, and the disobedient to the wisdom of the just; to make ready a people prepared for the Lord."'),
('Luke', 1, 'adults', 4, 'What Old Testament prophecy does the angel''s description of John fulfil?', 'Malachi 4:5-6 — the promise of Elijah returning to turn the hearts of the fathers to the children before the great day of the Lord', 'Isaiah 53 — the suffering servant', 'Psalm 22 — the cry of the forsaken', 'Daniel 9 — the seventy weeks prophecy', 'a', 'Luke 1:17 echoes Malachi 4:5-6 — "Behold, I will send you Elijah the prophet before the coming of the great and dreadful day of the LORD: And he shall turn the heart of the fathers to the children."'),
('Luke', 1, 'adults', 5, 'In Mary''s Magnificat, what does she say God has done to the proud?', 'He hath scattered the proud in the imagination of their hearts', 'He has rewarded the proud for their confidence', 'He has ignored the proud completely', 'He has promoted the proud to positions of power', 'a', 'Luke 1:51 — "He hath shewed strength with his arm; he hath scattered the proud in the imagination of their hearts."'),
('Luke', 1, 'adults', 6, 'What does Zacharias prophesy about the "horn of salvation" in the Benedictus?', 'God hath raised up an horn of salvation in the house of His servant David — as spoken by the holy prophets since the world began', 'A literal horn will appear in the temple', 'David himself will return to reign', 'A new military weapon will deliver Israel', 'a', 'Luke 1:69-70 — "And hath raised up an horn of salvation for us in the house of his servant David; As he spake by the mouth of his holy prophets, which have been since the world began."'),
('Luke', 1, 'adults', 7, 'What does Zacharias say John will give to God''s people?', 'Knowledge of salvation by the remission of their sins, through the tender mercy of our God', 'Political freedom from Roman rule', 'Great material wealth and prosperity', 'Military strategies for victory', 'a', 'Luke 1:77-78 — "To give knowledge of salvation unto his people by the remission of their sins, Through the tender mercy of our God; whereby the dayspring from on high hath visited us."'),
('Luke', 1, 'adults', 8, 'What is the theological significance of the "dayspring from on high" in Zacharias'' prophecy?', 'It refers to the Messiah as the rising sun from heaven — to give light to them that sit in darkness and in the shadow of death, and to guide our feet into the way of peace', 'It describes a literal sunrise over the temple', 'It refers to a new star appearing in the sky', 'It describes the spring season arriving early', 'a', 'Luke 1:78-79 — "The dayspring from on high hath visited us, To give light to them that sit in darkness and in the shadow of death, to guide our feet into the way of peace." The Greek "anatole" means sunrise/dawn, a messianic title.');

-- ═══ Luke Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 2, 'kids', 1, 'Where was baby Jesus laid after He was born?', 'In a manger', 'In a golden cradle', 'In a palace bed', 'In a basket on the river', 'a', 'Luke 2:7 — "And she brought forth her firstborn son, and wrapped him in swaddling clothes, and laid him in a manger; because there was no room for them in the inn."'),
('Luke', 2, 'kids', 2, 'Who did the angels appear to with the good news about Jesus'' birth?', 'Shepherds keeping watch over their flock by night', 'The king in his palace', 'Fishermen on the sea', 'Soldiers at the city gate', 'a', 'Luke 2:8-10 — "And there were in the same country shepherds abiding in the field, keeping watch over their flock by night. And, lo, the angel of the Lord came upon them."'),
('Luke', 2, 'kids', 3, 'What did the angels sing when they told the shepherds about Jesus?', 'Glory to God in the highest, and on earth peace, good will toward men', 'Happy birthday, dear Jesus', 'The Lord is my shepherd', 'Praise the king of the Romans', 'a', 'Luke 2:14 — "Glory to God in the highest, and on earth peace, good will toward men."'),
-- Teens
('Luke', 2, 'teens', 1, 'Why did Joseph and Mary travel to Bethlehem?', 'Caesar Augustus decreed that all the world should be taxed, and Joseph went to Bethlehem because he was of the house of David', 'They were fleeing from King Herod', 'They were visiting Mary''s parents', 'They wanted to celebrate Passover there', 'a', 'Luke 2:1-4 — "And it came to pass in those days, that there went out a decree from Caesar Augustus, that all the world should be taxed... And Joseph also went up from Galilee... unto Bethlehem; because he was of the house and lineage of David."'),
('Luke', 2, 'teens', 2, 'What did Simeon say when he held the baby Jesus in the temple?', 'Lord, now lettest thou thy servant depart in peace, for mine eyes have seen thy salvation', 'This child will be a great warrior', 'This child will become a wealthy merchant', 'This child will rebuild the temple', 'a', 'Luke 2:29-30 — "Lord, now lettest thou thy servant depart in peace, according to thy word: For mine eyes have seen thy salvation."'),
('Luke', 2, 'teens', 3, 'What prophecy did Simeon give Mary about Jesus?', 'A sword shall pierce through thy own soul also — and this child is set for the fall and rising again of many in Israel', 'Your son will become the richest man in the world', 'Your son will never face any hardship', 'Your son will rule as an earthly king immediately', 'a', 'Luke 2:34-35 — "Behold, this child is set for the fall and rising again of many in Israel; and for a sign which shall be spoken against; (Yea, a sword shall pierce through thy own soul also.)"'),
('Luke', 2, 'teens', 4, 'What did twelve-year-old Jesus say when His parents found Him in the temple?', 'Wist ye not that I must be about my Father''s business?', 'I was lost and could not find my way', 'I was playing with the other children', 'I was waiting for you to come back', 'a', 'Luke 2:49 — "And he said unto them, How is it that ye sought me? wist ye not that I must be about my Father''s business?"'),
('Luke', 2, 'teens', 5, 'How does Luke summarise Jesus'' growth as a child?', 'Jesus increased in wisdom and stature, and in favour with God and man', 'Jesus showed no sign of being special as a child', 'Jesus performed many miracles as a boy', 'Jesus spent all His time alone in prayer', 'a', 'Luke 2:52 — "And Jesus increased in wisdom and stature, and in favour with God and man."'),
-- Adults
('Luke', 2, 'adults', 1, 'What is the historical significance of Luke mentioning Caesar Augustus and the taxing decree?', 'It anchors the birth of Christ in verifiable world history — Luke, the careful historian, ties the incarnation to a specific Roman census under Augustus', 'It shows Jesus was born into a wealthy family', 'It proves Rome supported Christianity', 'It was included to flatter the Roman emperor', 'a', 'Luke 2:1-2 — "There went out a decree from Caesar Augustus, that all the world should be taxed. (And this taxing was first made when Cyrenius was governor of Syria.)" Luke uniquely ties sacred history to secular chronology.'),
('Luke', 2, 'adults', 2, 'What is the theological significance of God announcing Jesus'' birth to shepherds rather than to royalty?', 'It demonstrates God''s pattern of revealing salvation to the humble and lowly — shepherds were among the lowest social classes, reflecting Luke''s theme of gospel for the poor', 'Shepherds were the wealthiest class in Israel', 'There were no royalty nearby to tell', 'It was simply a random coincidence', 'a', 'Luke 2:8-12 — The announcement to shepherds fits Luke''s theme of good news for the poor and marginalized (cf. Luke 4:18, 6:20). God bypasses the powerful to reveal His Son to the humble.'),
('Luke', 2, 'adults', 3, 'What does the angel''s title for Jesus — "a Saviour, which is Christ the Lord" — combine?', 'Three distinct roles: Saviour (deliverer), Christ (Messiah/anointed one), and Lord (divine sovereign) — a uniquely comprehensive Christological declaration', 'Only a political title for Jewish kings', 'A common name used for Roman generals', 'A title reserved for temple priests', 'a', 'Luke 2:11 — "For unto you is born this day in the city of David a Saviour, which is Christ the Lord." This triple title uniquely combines soteriology (Saviour), messianic identity (Christ), and deity (Lord/Kyrios).'),
('Luke', 2, 'adults', 4, 'What does Simeon''s Nunc Dimittis reveal about the scope of salvation?', 'Salvation is prepared before the face of all people — a light to lighten the Gentiles, and the glory of God''s people Israel', 'Salvation is only for the Jewish nation', 'Salvation is only for temple worshippers', 'Salvation is limited to those in Jerusalem', 'a', 'Luke 2:30-32 — "For mine eyes have seen thy salvation, Which thou hast prepared before the face of all people; A light to lighten the Gentiles, and the glory of thy people Israel." Simeon sees both universal and particular aspects of salvation.'),
('Luke', 2, 'adults', 5, 'Who was the prophetess Anna, and what did she do upon seeing Jesus?', 'A prophetess, daughter of Phanuel of the tribe of Aser, who served God with fastings and prayers night and day — she gave thanks and spake of him to all that looked for redemption in Jerusalem', 'A Roman official''s wife who ignored Jesus', 'A wealthy merchant who offered gold', 'A scribe who recorded the event officially', 'a', 'Luke 2:36-38 — "And there was one Anna, a prophetess, the daughter of Phanuel, of the tribe of Aser... which departed not from the temple, but served God with fastings and prayers night and day. And she... gave thanks likewise unto the Lord, and spake of him to all them that looked for redemption in Jerusalem."'),
('Luke', 2, 'adults', 6, 'What does Simeon''s prophecy about a "sword" piercing Mary''s soul foreshadow?', 'Mary''s anguish at the crucifixion of her son — the revelation of Jesus as the suffering Messiah would bring her deep personal grief', 'A literal sword attack on Mary', 'Mary would become a warrior', 'Mary would leave Israel permanently', 'a', 'Luke 2:35 — "(Yea, a sword shall pierce through thy own soul also.)" This prophetically anticipates Mary standing at the cross (John 19:25), experiencing the suffering inherent in her son''s mission.'),
('Luke', 2, 'adults', 7, 'What does Jesus'' statement about being "about my Father''s business" at age twelve reveal?', 'Even as a child, Jesus had a conscious awareness of His unique divine sonship and His mission from the Father', 'Jesus was disobedient to His earthly parents', 'Jesus wanted to become a scribe', 'Jesus was confused about His identity', 'a', 'Luke 2:49 — "Wist ye not that I must be about my Father''s business?" This is Jesus'' first recorded words, revealing His self-awareness of His unique relationship with God as Father and His divine mission.'),
('Luke', 2, 'adults', 8, 'How does Luke 2:52 reflect the full humanity of Christ?', 'By stating that Jesus increased in wisdom, stature, and favour with God and man — showing genuine human development in every dimension: intellectual, physical, spiritual, and social', 'It suggests Jesus was not truly divine', 'It implies Jesus had limitations He never overcame', 'It shows Jesus was like any ordinary person with no special calling', 'a', 'Luke 2:52 — "And Jesus increased in wisdom and stature, and in favour with God and man." This verse affirms the orthodox doctrine that Jesus was fully human, experiencing real growth, while remaining fully divine.');

-- ═══ Luke Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 3, 'kids', 1, 'Who baptised people in the Jordan River and told them to repent?', 'John the Baptist', 'Peter', 'Moses', 'Elijah', 'a', 'Luke 3:3 — "And he came into all the country about Jordan, preaching the baptism of repentance for the remission of sins."'),
('Luke', 3, 'kids', 2, 'What came down from heaven when Jesus was baptised?', 'The Holy Ghost in the shape of a dove', 'A golden crown', 'Fire from the sky', 'A bright rainbow', 'a', 'Luke 3:22 — "And the Holy Ghost descended in a bodily shape like a dove upon him, and a voice came from heaven, which said, Thou art my beloved Son; in thee I am well pleased."'),
('Luke', 3, 'kids', 3, 'What did the voice from heaven say when Jesus was baptised?', 'Thou art my beloved Son; in thee I am well pleased', 'This is a great prophet', 'This is the king of Israel', 'This man will rule the world', 'a', 'Luke 3:22 — "And a voice came from heaven, which said, Thou art my beloved Son; in thee I am well pleased."'),
-- Teens
('Luke', 3, 'teens', 1, 'What Old Testament passage does Luke quote about John the Baptist?', 'The voice of one crying in the wilderness, Prepare ye the way of the Lord, make his paths straight — from Isaiah 40:3', 'The Lord is my shepherd — from Psalm 23', 'In the beginning God created — from Genesis 1', 'Behold the Lamb of God — from Isaiah 53', 'a', 'Luke 3:4 — "As it is written in the book of the words of Esaias the prophet, saying, The voice of one crying in the wilderness, Prepare ye the way of the Lord, make his paths straight."'),
('Luke', 3, 'teens', 2, 'What did John tell people who had two coats?', 'He that hath two coats, let him impart to him that hath none; and he that hath meat, let him do likewise', 'Keep both coats for yourself', 'Sell both and give the money to the temple', 'Give them both to the priests', 'a', 'Luke 3:11 — "He that hath two coats, let him impart to him that hath none; and he that hath meat, let him do likewise."'),
('Luke', 3, 'teens', 3, 'What did John say about the One coming after him?', 'One mightier than I cometh, the latchet of whose shoes I am not worthy to unloose: he shall baptize you with the Holy Ghost and with fire', 'Someone who will be weaker than me', 'A political leader who will overthrow Rome', 'A priest who will rebuild the temple', 'a', 'Luke 3:16 — "John answered, saying unto them all, I indeed baptize you with water; but one mightier than I cometh, the latchet of whose shoes I am not worthy to unloose: he shall baptize you with the Holy Ghost and with fire."'),
('Luke', 3, 'teens', 4, 'What did John tell the publicans (tax collectors) who came to be baptised?', 'Exact no more than that which is appointed you — collect only what is required', 'Stop collecting taxes entirely', 'Give all the money to the poor', 'Leave your job immediately', 'a', 'Luke 3:13 — "And he said unto them, Exact no more than that which is appointed you."'),
('Luke', 3, 'teens', 5, 'How far back does Luke trace Jesus'' genealogy?', 'All the way back to Adam, which was the son of God', 'Back to Abraham only', 'Back to David only', 'Back to Moses only', 'a', 'Luke 3:38 — "Which was the son of Enos, which was the son of Seth, which was the son of Adam, which was the son of God." Luke traces Jesus'' line back to Adam, emphasizing Jesus as the Saviour of all humanity.'),
-- Adults
('Luke', 3, 'adults', 1, 'Why does Luke provide such precise historical dating in verses 1-2?', 'To establish the reliability of his account by anchoring John''s ministry in verifiable history — naming Tiberius Caesar, Pontius Pilate, Herod, Philip, Lysanias, and the high priests Annas and Caiaphas', 'To impress wealthy Roman readers', 'To show off his knowledge of politics', 'To fill space in his manuscript', 'a', 'Luke 3:1-2 — Luke names six political rulers and two high priests, providing a sixfold synchronism that precisely dates the beginning of John''s ministry to approximately AD 28-29.'),
('Luke', 3, 'adults', 2, 'What is significant about Luke extending the Isaiah 40 quotation further than Matthew and Mark?', 'Luke alone includes "all flesh shall see the salvation of God" — emphasising the universal scope of salvation, consistent with his Gentile audience and theme of gospel for all peoples', 'Luke made an error in his quotation', 'Luke was quoting a different passage', 'There is no difference between the Gospel accounts', 'a', 'Luke 3:6 — "And all flesh shall see the salvation of God." Matthew and Mark stop earlier, but Luke extends to Isaiah 40:5, highlighting universality — a key Lukan theme.'),
('Luke', 3, 'adults', 3, 'What does John mean by "fruits worthy of repentance"?', 'Genuine repentance must produce visible evidence in changed behaviour — not mere words or religious heritage, as shown by his specific ethical instructions to crowds, publicans, and soldiers', 'Literal fruit must be brought as an offering', 'Repentance is only an internal feeling', 'Only priests need to show repentance', 'a', 'Luke 3:8 — "Bring forth therefore fruits worthy of repentance, and begin not to say within yourselves, We have Abraham to our father." John demands concrete ethical change, not reliance on Abrahamic descent.'),
('Luke', 3, 'adults', 4, 'What does the image of the "fan in his hand" and "unquenchable fire" signify about the coming Messiah?', 'The Messiah will be a judge who separates the righteous from the wicked — the winnowing fan separates wheat from chaff, and the unquenchable fire represents final judgment', 'Jesus will be a farmer', 'Jesus will bring literal fire to earth', 'John was confused about Jesus'' role', 'a', 'Luke 3:17 — "Whose fan is in his hand, and he will throughly purge his floor, and will gather the wheat into his garner; but the chaff he will burn with fire unquenchable." This is an agricultural metaphor for eschatological judgment.'),
('Luke', 3, 'adults', 5, 'What is the theological significance of all three Persons of the Trinity being present at Jesus'' baptism?', 'It is a Trinitarian theophany — the Son is baptised, the Spirit descends as a dove, and the Father speaks from heaven, revealing the triune nature of God in one event', 'It was merely a coincidence', 'Only one person of God was present', 'The Trinity doctrine was invented later', 'a', 'Luke 3:21-22 — Jesus (Son) is praying, the Holy Ghost descends in bodily shape like a dove, and the Father''s voice declares from heaven. This is one of the clearest Trinitarian revelations in the Gospels.'),
('Luke', 3, 'adults', 6, 'Why does Luke''s genealogy differ from Matthew''s, and what is its theological purpose?', 'Luke likely traces Jesus'' line through Mary (Heli being Mary''s father), going back to Adam to show Jesus as Saviour of all humanity — whereas Matthew traces through Joseph to David and Abraham for a Jewish audience', 'Luke made errors in his genealogy', 'The two genealogies are completely contradictory', 'Luke copied Matthew and changed names', 'a', 'Luke 3:23-38 — Luke''s genealogy ascends from Jesus to Adam ("son of God"), emphasising universal humanity. Matthew descends from Abraham to Jesus, emphasising Jewish kingship. The traditional view is that Luke traces Mary''s line.'),
('Luke', 3, 'adults', 7, 'What does John''s rebuke "who hath warned you to flee from the wrath to come" imply about his audience?', 'Some came for baptism as a religious formality without genuine repentance — John challenged their motives and demanded authentic heart change', 'Everyone who came was genuinely repentant', 'John was refusing to baptise anyone', 'John was surprised anyone came at all', 'a', 'Luke 3:7 — "Then said he to the multitude that came forth to be baptized of him, O generation of vipers, who hath warned you to flee from the wrath to come?" John discerns superficial religion and demands genuine transformation.'),
('Luke', 3, 'adults', 8, 'Why was Herod''s imprisonment of John significant for Luke''s narrative?', 'Luke mentions it before the baptism account to close John''s ministry section before opening Jesus'' public ministry — showing the transition from the old prophetic era to the new messianic age', 'Luke made a chronological error', 'It was unimportant to the narrative', 'Luke wanted to criticise Roman politics', 'a', 'Luke 3:19-20 — By mentioning Herod''s imprisonment of John before narrating Jesus'' baptism (v.21), Luke literarily closes the Baptist''s ministry, marking the decisive transition from preparation to fulfilment.');

-- ═══════════════ CHAPTERS 4–6 ═══════════════

-- ═══ Luke Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 4, 'kids', 1, 'Who tempted Jesus in the wilderness?', 'The devil', 'A Roman soldier', 'A Pharisee', 'An angel', 'a', 'Luke 4:2 — "Being forty days tempted of the devil."'),
('Luke', 4, 'kids', 2, 'How long did Jesus fast in the wilderness?', 'Forty days', 'Seven days', 'Three days', 'Ten days', 'a', 'Luke 4:2 — "Being forty days tempted of the devil. And in those days he did eat nothing."'),
('Luke', 4, 'kids', 3, 'What happened when Jesus read from the scroll in the synagogue at Nazareth?', 'The people were angry and tried to push Him off a cliff', 'The people cheered and crowned Him king', 'The people fell asleep', 'The people gave Him money', 'a', 'Luke 4:28-29 — "And all they in the synagogue, when they heard these things, were filled with wrath, And rose up, and thrust him out of the city, and led him unto the brow of the hill... that they might cast him down headlong."'),
-- Teens
('Luke', 4, 'teens', 1, 'What did Jesus answer when the devil tempted Him to turn stones into bread?', 'It is written, That man shall not live by bread alone, but by every word of God', 'I am too tired to use my power', 'I will eat after you leave', 'Bread is not important to me', 'a', 'Luke 4:4 — "And Jesus answered him, saying, It is written, That man shall not live by bread alone, but by every word of God."'),
('Luke', 4, 'teens', 2, 'What passage from Isaiah did Jesus read in the Nazareth synagogue?', 'The Spirit of the Lord is upon me, because he hath anointed me to preach the gospel to the poor', 'In the beginning God created the heaven and the earth', 'The Lord is my shepherd, I shall not want', 'Thou shalt have no other gods before me', 'a', 'Luke 4:18 — "The Spirit of the Lord is upon me, because he hath anointed me to preach the gospel to the poor; he hath sent me to heal the brokenhearted, to preach deliverance to the captives, and recovering of sight to the blind, to set at liberty them that are bruised."'),
('Luke', 4, 'teens', 3, 'What did Jesus declare after reading the Isaiah scroll?', 'This day is this scripture fulfilled in your ears', 'This scripture is about a future prophet', 'This passage has already been fulfilled by Elijah', 'This does not apply to anyone alive today', 'a', 'Luke 4:21 — "And he began to say unto them, This day is this scripture fulfilled in your ears."'),
('Luke', 4, 'teens', 4, 'What proverb did Jesus say the people of Nazareth would use against Him?', 'Physician, heal thyself — and No prophet is accepted in his own country', 'A rolling stone gathers no moss', 'Pride goeth before a fall', 'The early bird catches the worm', 'a', 'Luke 4:23-24 — "Ye will surely say unto me this proverb, Physician, heal thyself... Verily I say unto you, No prophet is accepted in his own country."'),
('Luke', 4, 'teens', 5, 'What examples did Jesus use of God sending prophets to Gentiles instead of Israelites?', 'Elijah was sent to a widow in Sidon, and Elisha healed Naaman the Syrian — both were Gentiles', 'Moses was sent to Egypt, and Joshua to Jericho', 'David fled to Moab, and Solomon traded with Tyre', 'Jonah went to Nineveh, and Daniel to Babylon', 'a', 'Luke 4:25-27 — Jesus cites the widow of Sarepta (Sidon) who hosted Elijah (1 Kings 17) and Naaman the Syrian cleansed by Elisha (2 Kings 5), showing God''s grace extends to Gentiles.'),
-- Adults
('Luke', 4, 'adults', 1, 'How does Luke''s order of the three temptations differ from Matthew''s, and what is the significance?', 'Luke places the temple temptation last (climaxing in Jerusalem), while Matthew places the mountain temptation last — Luke''s order reflects his theological emphasis on Jerusalem as the destination of Jesus'' ministry', 'There is no difference between the accounts', 'Luke omits one of the temptations', 'Matthew added an extra temptation', 'a', 'Luke 4:9-12 — Luke''s third temptation is at the Jerusalem temple, while Matthew ends with the mountain vision. Luke''s Jerusalem-centric structure anticipates his travel narrative (9:51) where Jesus resolutely heads to Jerusalem.'),
('Luke', 4, 'adults', 2, 'What is the significance of Jesus stopping mid-sentence when reading Isaiah 61 in the synagogue?', 'Jesus read "the acceptable year of the Lord" but stopped before "the day of vengeance of our God" — indicating that His first coming brings salvation and grace, with judgment reserved for the second coming', 'Jesus lost his place in the scroll', 'The scroll was damaged at that point', 'Jesus was interrupted by the congregation', 'a', 'Luke 4:19 — Jesus reads Isaiah 61:1-2a but stops before 61:2b ("the day of vengeance of our God"). This deliberate omission distinguishes the first advent (grace) from the second (judgment).'),
('Luke', 4, 'adults', 3, 'What does Jesus'' use of the Elijah and Elisha examples reveal about His mission?', 'God''s saving work extends beyond Israel to Gentiles — Jesus provocatively reminds Nazareth that God bypassed many Israelites to bless Gentile outsiders, foreshadowing the Gentile mission', 'Jesus was simply teaching Old Testament history', 'Jesus was praising Nazareth''s faithfulness', 'Jesus wanted to start a political revolution', 'a', 'Luke 4:25-27 — By citing the Sidonian widow and Naaman, Jesus implies that unbelieving Israel may be passed over in favour of believing Gentiles — a theme central to Luke-Acts.'),
('Luke', 4, 'adults', 4, 'What does the phrase "he passing through the midst of them went his way" suggest?', 'A supernatural escape — Jesus walked through the hostile crowd unharmed, suggesting divine protection because His hour had not yet come', 'Jesus ran away quickly', 'The crowd simply lost interest', 'Jesus disguised himself and escaped', 'a', 'Luke 4:30 — "But he passing through the midst of them went his way." The calm, sovereign manner of escape implies miraculous deliverance, echoing John 7:30 and 8:59.'),
('Luke', 4, 'adults', 5, 'What did the demons in the synagogue at Capernaum recognise about Jesus?', 'They knew He was "the Holy One of God" and "Christ" — the demons possessed supernatural knowledge of Jesus'' true identity before many humans recognised it', 'They thought He was just a prophet', 'They did not recognise Him at all', 'They believed He was John the Baptist', 'a', 'Luke 4:34,41 — "I know thee who thou art; the Holy One of God" (v.34) and "Thou art Christ the Son of God" (v.41). Ironically, demonic testimony precedes human confession.'),
('Luke', 4, 'adults', 6, 'Why did Jesus command the demons to be silent about His identity?', 'Jesus did not want His messianic identity proclaimed by demons — the "messianic secret" prevented premature disclosure that could lead to misunderstanding of His mission as political rather than redemptive', 'Jesus was not sure of His own identity', 'The demons were lying about who He was', 'Jesus wanted to keep a low profile for safety', 'a', 'Luke 4:35,41 — "He rebuking them suffered them not to speak: for they knew that he was Christ." Jesus controls the timing and manner of His self-revelation, refusing demonic testimony.'),
('Luke', 4, 'adults', 7, 'What does Jesus'' healing of Simon''s wife''s mother demonstrate about His power?', 'Jesus rebuked the fever and it left her immediately, and she arose and ministered unto them — showing authority over disease comparable to His authority over demons', 'Jesus used medicine to heal her', 'The fever went away on its own', 'Peter''s prayer healed her, not Jesus', 'a', 'Luke 4:39 — "And he stood over her, and rebuked the fever; and it left her: and immediately she arose and ministered unto them." Luke uniquely uses "rebuked" (the same word used for demons), showing Jesus'' sovereign authority over all affliction.'),
('Luke', 4, 'adults', 8, 'What does Jesus'' statement "I must preach the kingdom of God to other cities also: for therefore am I sent" reveal about His priorities?', 'Preaching the kingdom of God was the primary purpose of Jesus'' mission — healing was a sign, but proclamation of the kingdom was His central calling', 'Jesus was tired of healing and wanted to do something else', 'Jesus preferred larger cities over small towns', 'Jesus was running from His enemies', 'a', 'Luke 4:43 — "I must preach the kingdom of God to other cities also: for therefore am I sent." Jesus defines His mission as proclamation, not merely miraculous works, preventing a mere wonder-worker reputation.');

-- ═══ Luke Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 5, 'kids', 1, 'What miracle happened when Jesus told Simon Peter to let down his nets?', 'They caught so many fish that the nets began to break', 'The water turned into wine', 'The fish jumped onto the boat', 'The nets turned into gold', 'a', 'Luke 5:6 — "And when they had this done, they inclosed a great multitude of fishes: and their net brake."'),
('Luke', 5, 'kids', 2, 'How did some friends get a sick man to Jesus when the house was too crowded?', 'They lowered him through the roof on his bed', 'They pushed through the front door', 'They waited outside until everyone left', 'They called Jesus to come outside', 'a', 'Luke 5:19 — "And when they could not find by what way they might bring him in because of the multitude, they went upon the housetop, and let him down through the tiling with his couch into the midst before Jesus."'),
('Luke', 5, 'kids', 3, 'What did Jesus say to the paralysed man?', 'Man, thy sins are forgiven thee', 'Stand up and dance', 'Go home and rest', 'Your friends have saved you', 'a', 'Luke 5:20 — "And when he saw their faith, he said unto him, Man, thy sins are forgiven thee."'),
-- Teens
('Luke', 5, 'teens', 1, 'What did Peter say to Jesus after seeing the miraculous catch of fish?', 'Depart from me; for I am a sinful man, O Lord', 'Thank you for all these fish', 'Let us sell these fish for a great price', 'I knew you could do this all along', 'a', 'Luke 5:8 — "When Simon Peter saw it, he fell down at Jesus'' knees, saying, Depart from me; for I am a sinful man, O Lord."'),
('Luke', 5, 'teens', 2, 'What did Jesus promise Simon Peter after the miraculous catch?', 'From henceforth thou shalt catch men — Jesus called him to become a fisher of men', 'You will become the richest fisherman in Galilee', 'You will never have to fish again', 'You will own all the boats on the sea', 'a', 'Luke 5:10 — "And Jesus said unto Simon, Fear not; from henceforth thou shalt catch men."'),
('Luke', 5, 'teens', 3, 'Why were the Pharisees upset when Jesus forgave the paralysed man''s sins?', 'They believed only God can forgive sins, so Jesus was claiming to be God — which they considered blasphemy', 'They were upset the man was healed', 'They thought Jesus should charge money', 'They wanted to forgive the man themselves', 'a', 'Luke 5:21 — "And the scribes and the Pharisees began to reason, saying, Who is this which speaketh blasphemies? Who can forgive sins, but God alone?"'),
('Luke', 5, 'teens', 4, 'What tax collector did Jesus call to follow Him?', 'Levi (also called Matthew), who was sitting at the receipt of custom', 'Zacchaeus from Jericho', 'Nicodemus the Pharisee', 'Joseph of Arimathaea', 'a', 'Luke 5:27 — "And after these things he went forth, and saw a publican, named Levi, sitting at the receipt of custom: and he said unto him, Follow me."'),
('Luke', 5, 'teens', 5, 'What did Jesus say about who He came to call?', 'They that are whole need not a physician; but they that are sick — I came not to call the righteous, but sinners to repentance', 'I came to call the most religious people', 'I came to call the wealthiest citizens', 'I came to call the strongest warriors', 'a', 'Luke 5:31-32 — "They that are whole need not a physician; but they that are sick. I came not to call the righteous, but sinners to repentance."'),
-- Adults
('Luke', 5, 'adults', 1, 'What is the theological significance of Peter''s response "Depart from me; for I am a sinful man, O Lord"?', 'It echoes Old Testament theophanies (Isaiah 6:5) — Peter''s awareness of his sinfulness in the presence of divine holiness shows he recognises Jesus as more than human', 'Peter was simply being modest', 'Peter was afraid of drowning', 'Peter wanted Jesus to leave so he could sell the fish', 'a', 'Luke 5:8 — Peter''s reaction mirrors Isaiah''s "Woe is me! for I am undone" (Isaiah 6:5). The miraculous catch reveals Jesus'' divine authority, provoking the proper human response to holiness: conviction of sin.'),
('Luke', 5, 'adults', 2, 'How does the healing of the leper demonstrate both Jesus'' compassion and His respect for the Mosaic law?', 'Jesus touched the leper (showing compassion to the untouchable) but then told him to show himself to the priest and offer the gift Moses commanded — honouring the law while transcending its boundaries', 'Jesus avoided the leper completely', 'Jesus told the leper to ignore the law', 'Jesus healed him from a distance and gave no further instructions', 'a', 'Luke 5:13-14 — "And he put forth his hand, and touched him... and immediately the leprosy departed... go, and shew thyself to the priest, and offer for thy cleansing, according as Moses commanded, for a testimony unto them."'),
('Luke', 5, 'adults', 3, 'What does Jesus'' question "Whether is easier, to say, Thy sins be forgiven thee; or to say, Rise up and walk?" prove about His authority?', 'The visible miracle (healing) validates the invisible one (forgiveness) — since both require divine power, the observable healing proves Jesus has the unseen authority to forgive sins', 'Healing is easier than forgiving sins', 'Forgiving sins is easier than healing', 'Neither requires any real power', 'a', 'Luke 5:23-24 — Jesus uses the irrefutable visible miracle to authenticate the contested invisible claim. If He can do the harder-to-verify act (forgiveness), He can certainly do the easier-to-verify one (healing).'),
('Luke', 5, 'adults', 4, 'What is the significance of the title "Son of man" that Jesus uses in verse 24?', 'It is Jesus'' preferred self-designation, drawn from Daniel 7:13-14, combining humanity with divine authority — "the Son of man hath power upon earth to forgive sins"', 'It simply means Jesus is a human being', 'It is a title of weakness and humility only', 'It was a common nickname in first-century Judaism', 'a', 'Luke 5:24 — "That ye may know that the Son of man hath power upon earth to forgive sins." The title from Daniel 7:13-14 denotes one who receives everlasting dominion from the Ancient of Days — a claim to divine authority.'),
('Luke', 5, 'adults', 5, 'What does Levi''s great feast for Jesus reveal about his response to the call?', 'Levi immediately left everything, followed Jesus, and then used his resources and social connections to introduce other tax collectors and sinners to Jesus — evangelism through hospitality', 'Levi was simply showing off his wealth', 'Levi was trying to bribe Jesus', 'Levi wanted to prove he was still wealthy', 'a', 'Luke 5:28-29 — "And he left all, rose up, and followed him. And Levi made him a great feast in his own house: and there was a great company of publicans and of others that sat down with them." Levi''s first act as a disciple is evangelistic outreach.'),
('Luke', 5, 'adults', 6, 'What does the parable of the new wine in old bottles (wineskins) teach in context?', 'Jesus'' teaching and ministry represent something radically new that cannot be contained within the rigid forms of Pharisaic Judaism — new wine needs new wineskins', 'Wine should always be stored in old bottles', 'The Pharisees'' traditions were better than Jesus'' teaching', 'There is no real difference between old and new', 'a', 'Luke 5:37-38 — "And no man putteth new wine into old bottles; else the new wine will burst the bottles... But new wine must be put into new bottles." The gospel of grace cannot be confined to legalistic structures.'),
('Luke', 5, 'adults', 7, 'What does the phrase "they forsook all, and followed him" (v.11) tell us about the cost of discipleship?', 'True discipleship requires total abandonment of former securities — Peter, James, and John left their nets, boats, and livelihood at the peak of success (a miraculous catch) to follow Jesus', 'They only followed Jesus part-time', 'They brought their fishing business with them', 'They planned to return to fishing later', 'a', 'Luke 5:11 — "And when they had brought their ships to land, they forsook all, and followed him." The greatest catch of their careers became the moment they walked away from fishing forever.'),
('Luke', 5, 'adults', 8, 'What does verse 39 — "No man also having drunk old wine straightway desireth new: for he saith, The old is better" — mean in context?', 'It acknowledges the difficulty of accepting new revelation when attached to familiar traditions — people naturally prefer what they are accustomed to, explaining why the religious establishment resisted Jesus', 'Old wine is always better than new wine', 'Jesus was recommending aged wine', 'The Pharisees had better theology than Jesus', 'a', 'Luke 5:39 — This proverb explains why the Pharisees and John''s disciples struggled with Jesus'' new approach. Human nature clings to the familiar. Jesus acknowledges this tendency without endorsing the old over the new.');

-- ═══ Luke Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 6, 'kids', 1, 'What did Jesus say is the Golden Rule?', 'As ye would that men should do to you, do ye also to them likewise — treat others the way you want to be treated', 'Always eat your vegetables', 'Go to bed early every night', 'Never talk to strangers', 'a', 'Luke 6:31 — "And as ye would that men should do to you, do ye also to them likewise."'),
('Luke', 6, 'kids', 2, 'What did Jesus say we should do to our enemies?', 'Love your enemies, do good to them which hate you', 'Fight them and win', 'Ignore them and hide', 'Tell on them to someone bigger', 'a', 'Luke 6:27 — "But I say unto you which hear, Love your enemies, do good to them which hate you."'),
('Luke', 6, 'kids', 3, 'What happens to the house that is built without a good foundation?', 'It falls down and is completely ruined', 'It becomes the strongest house', 'It floats away on the water', 'It turns into a palace', 'a', 'Luke 6:49 — "But he that heareth, and doeth not, is like a man that without a foundation built an house upon the earth; against which the stream did beat vehemently, and immediately it fell; and the ruin of that house was great."'),
-- Teens
('Luke', 6, 'teens', 1, 'What did Jesus say about judging others?', 'Judge not, and ye shall not be judged: condemn not, and ye shall not be condemned: forgive, and ye shall be forgiven', 'Always judge others so you can correct them', 'Judging is only for the Pharisees', 'Never form any opinion about anyone', 'a', 'Luke 6:37 — "Judge not, and ye shall not be judged: condemn not, and ye shall not be condemned: forgive, and ye shall be forgiven."'),
('Luke', 6, 'teens', 2, 'What did Jesus say about giving?', 'Give, and it shall be given unto you; good measure, pressed down, and shaken together, and running over', 'Give only to people who can pay you back', 'Never give anything away', 'Give only when forced to', 'a', 'Luke 6:38 — "Give, and it shall be given unto you; good measure, pressed down, and shaken together, and running over, shall men give into your bosom."'),
('Luke', 6, 'teens', 3, 'What illustration did Jesus use about a speck and a beam?', 'Do not try to remove the mote (speck) from your brother''s eye when you have a beam (log) in your own eye — deal with your own faults first', 'Always help others before yourself', 'Only carpenters should handle beams', 'Eye problems should be treated by doctors only', 'a', 'Luke 6:41-42 — "And why beholdest thou the mote that is in thy brother''s eye, but perceivest not the beam that is in thine own eye?"'),
('Luke', 6, 'teens', 4, 'What did Jesus say about a tree and its fruit?', 'Every good tree bringeth forth good fruit — you can tell what a person is like by what they produce', 'Bad trees sometimes produce good fruit', 'You cannot tell anything about a tree from its fruit', 'All trees produce the same fruit', 'a', 'Luke 6:43-44 — "For a good tree bringeth not forth corrupt fruit; neither doth a corrupt tree bring forth good fruit. For every tree is known by his own fruit."'),
('Luke', 6, 'teens', 5, 'What challenge did Jesus give to those who call Him "Lord"?', 'Why call ye me, Lord, Lord, and do not the things which I say? — obedience must match confession', 'As long as you call Him Lord, your actions do not matter', 'Only say Lord once, not twice', 'Calling Him Lord is all you need to do', 'a', 'Luke 6:46 — "And why call ye me, Lord, Lord, and do not the things which I say?"'),
-- Adults
('Luke', 6, 'adults', 1, 'What did Jesus mean by declaring Himself "Lord also of the sabbath"?', 'As the Son of Man, Jesus has divine authority over the Sabbath — He who instituted it has the right to define its proper use, placing His authority above Pharisaic tradition', 'Jesus was abolishing the Sabbath entirely', 'Jesus was just another rabbi with an opinion', 'The Sabbath was no longer important', 'a', 'Luke 6:5 — "And he said unto them, That the Son of man is Lord also of the sabbath." This claim to lordship over a divine institution is an implicit claim to deity.'),
('Luke', 6, 'adults', 2, 'How does Luke''s Sermon on the Plain (6:20-49) compare with Matthew''s Sermon on the Mount?', 'Luke''s version is shorter, uses second person ("Blessed be ye poor"), includes woes alongside blessings, and emphasises socioeconomic themes — reflecting Luke''s concern for the poor and marginalized', 'They are identical in every detail', 'Luke''s version is longer than Matthew''s', 'Luke copied Matthew word for word', 'a', 'Luke 6:20 — "Blessed be ye poor: for yours is the kingdom of God." Unlike Matthew''s "poor in spirit," Luke''s direct address to the literally poor fits his theme of reversal (1:52-53). The parallel woes (6:24-26) strengthen the contrast.'),
('Luke', 6, 'adults', 3, 'What is the significance of the four "woes" in Luke 6:24-26?', 'They reverse the four beatitudes — warning the rich, full, laughing, and well-spoken-of that present comfort may indicate spiritual danger, echoing the prophetic tradition of pronouncing judgment', 'Jesus was condemning all wealthy people', 'The woes were added by a later editor', 'They only applied to Romans', 'a', 'Luke 6:24-26 — "But woe unto you that are rich!... Woe unto you that are full!... Woe unto you that laugh now!... Woe unto you, when all men shall speak well of you!" These woes, unique to Luke, parallel OT prophetic oracles.'),
('Luke', 6, 'adults', 4, 'What radical ethic does Jesus teach about loving enemies that goes beyond the Old Testament?', 'Love, do good, bless, and pray for those who hate, curse, despitefully use, and persecute you — a fourfold response of grace that transcends the lex talionis and natural human reciprocity', 'Simply avoid your enemies', 'Only love enemies who repent first', 'Love enemies in theory but not in practice', 'a', 'Luke 6:27-28 — "Love your enemies, do good to them which hate you, Bless them that curse you, and pray for them which despitefully use you." Jesus commands active benevolence, not merely passive tolerance.'),
('Luke', 6, 'adults', 5, 'What does Jesus'' command to "lend, hoping for nothing again" teach about Christian generosity?', 'Believers should lend without expecting repayment — true generosity is not a transaction but reflects the character of God, who "is kind unto the unthankful and to the evil"', 'Christians should never lend money', 'Only lend to people who can repay', 'Lending must always include interest', 'a', 'Luke 6:35 — "But love ye your enemies, and do good, and lend, hoping for nothing again; and your reward shall be great, and ye shall be the children of the Highest: for he is kind unto the unthankful and to the evil."'),
('Luke', 6, 'adults', 6, 'What does "Be ye therefore merciful, as your Father also is merciful" establish as the standard for ethics?', 'God''s own character is the standard — believers are to imitate divine mercy, not merely follow rules, making theomorphic ethics (God-likeness) the basis of conduct', 'Human consensus determines morality', 'Cultural norms define right and wrong', 'Personal feelings are the ultimate guide', 'a', 'Luke 6:36 — "Be ye therefore merciful, as your Father also is merciful." The parallel in Matthew 5:48 says "perfect." Luke''s emphasis on mercy fits his Gospel''s compassion theme.'),
('Luke', 6, 'adults', 7, 'What does the parable of the blind leading the blind teach about spiritual leadership?', 'An unqualified teacher will lead followers into the same ditch — spiritual leaders must first see clearly themselves before guiding others, as the disciple is not above his master', 'All leaders are equally qualified', 'Blindness is irrelevant to teaching', 'Students should teach their teachers', 'a', 'Luke 6:39-40 — "Can the blind lead the blind? shall they not both fall into the ditch? The disciple is not above his master: but every one that is perfect shall be as his master."'),
('Luke', 6, 'adults', 8, 'What is the parable of the two builders teaching about the relationship between hearing and doing?', 'True faith requires both hearing and obeying Jesus'' words — the one who hears and does builds on rock and withstands storms, while the one who hears but does not obey builds without foundation and faces ruin', 'Simply hearing Jesus'' words is sufficient', 'Building a physical house guarantees salvation', 'The parable is about construction techniques only', 'a', 'Luke 6:47-49 — "Whosoever cometh to me, and heareth my sayings, and doeth them... is like a man which built an house, and digged deep, and laid the foundation on a rock." The test of discipleship is obedience, not mere knowledge.');
